import requests
import subprocess
import json
import psutil
from typing import Dict, List, Optional
from dataclasses import dataclass

@dataclass
class QuantizationProfile:
    model_name: str
    quantization: str  # Q4_K_M, Q4_K_S, Q8_0, etc.
    memory_usage: float  # Estimated GB
    performance_score: float  # Relative performance (0-1)
    supported_ops: List[str]  # Supported operations

class DynamicQuantizationManager:
    """
    Hardware-aware quantization management for Ollama models
    """

    def __init__(self, ollama_base_url: str = "http://localhost:11434"):
        self.ollama_url = ollama_base_url
        self.gpu_memory = self._detect_gpu_memory()
        self.system_memory = psutil.virtual_memory().total / (1024**3)

        # Quantization profiles optimized for consumer hardware
        self.profiles = {
            'Q4_K_M': {'memory_mult': 0.57, 'performance': 0.95, 'speed': 1.0},
            'Q4_K_S': {'memory_mult': 0.54, 'performance': 0.92, 'speed': 1.05},
            'Q5_K_M': {'memory_mult': 0.71, 'performance': 0.98, 'speed': 0.9},
            'Q8_0': {'memory_mult': 1.0, 'performance': 1.0, 'speed': 0.8},
            'Q3_K_M': {'memory_mult': 0.42, 'performance': 0.88, 'speed': 1.15}
        }

    def _detect_gpu_memory(self) -> float:
        """Detect available GPU memory"""
        try:
            # Try to get GPU info from system
            result = subprocess.run(['nvidia-smi', '--query-gpu=memory.total', '--format=csv,nounits,noheader'],
                                    capture_output=True, text=True)
            if result.returncode == 0:
                return float(result.stdout.strip()) / 1024  # Convert MB to GB
        except:
            pass
        # Fallback estimation
        return 12.0  # Conservative estimate

    def recommend_quantization(self, model_base: str, target_context: int = 4096,
                               priority: str = 'balanced') -> Dict[str, str]:
        """Recommend optimal quantization based on hardware and requirements"""
        # Estimate base model size (7B parameter model ≈ 14GB in FP16)
        base_size_gb = 14.0
        if '13b' in model_base.lower():
            base_size_gb = 26.0
        elif '3b' in model_base.lower() or '2b' in model_base.lower():
            base_size_gb = 6.0
        elif '70b' in model_base.lower():
            base_size_gb = 140.0

        # Context memory estimation (rough approximation)
        context_memory_gb = (target_context * 4) /(1024**3)  # 4 bytes per token roughly

        available_memory = min(self.gpu_memory * 0.8, self.system_memory * 0.4)  # Conservative

        recommendations = {}
        for quant_name, profile in self.profiles.items():
            estimated_usage = (base_size_gb * profile['memory_mult']) + context_memory_gb
            if estimated_usage <= available_memory:
                model_name = f"{model_base}:{quant_name}"
                recommendations[model_name] = {
                    'quantization': quant_name,
                    'estimated_memory': estimated_usage,
                    'performance_score': profile['performance'],
                    'speed_multiplier': profile['speed'],
                    'fits_in_memory': True
                }

        # Sort by priority
        if priority == 'speed':
            best = max(recommendations.items(), key=lambda x: x[1]['speed_multiplier']) if recommendations else (None, None)
        elif priority == 'quality':
            best = max(recommendations.items(), key=lambda x: x[1]['performance_score']) if recommendations else (None, None)
        else:  # balanced
            best = max(recommendations.items(),
                       key=lambda x: x[1]['performance_score'] * x[1]['speed_multiplier']) if recommendations else (None, None)

        return {
            'recommended_model': best[0],
            'alternatives': list(recommendations.keys())[:3],
            'estimated_memory_usage': best[1]['estimated_memory'] if best[1] else None,
            'available_memory': available_memory
        }

    def ensure_model_available(self, model_name: str) -> bool:
        """Ensure the specified quantized model is available in Ollama"""
        try:
            # Check if model is already pulled
            response = requests.get(f"{self.ollama_url}/api/tags", timeout=5)
            if response.status_code == 200:
                existing_models = [model['name'] for model in response.json().get('models', [])]
                if model_name in existing_models:
                    return True

            # Pull the model if not available
            print(f"Pulling model {model_name}...")
            pull_response = requests.post(
                f"{self.ollama_url}/api/pull",
                json={'name': model_name},
                timeout=30
            )
            return pull_response.status_code == 200
        except Exception as e:
            print(f"Error ensuring model availability: {e}")
            return False

    def get_model_info(self, model_name: str) -> Optional[Dict]:
        """Get information about a specific model"""
        try:
            response = requests.get(f"{self.ollama_url}/api/tags", timeout=5)
            if response.status_code == 200:
                models = response.json().get('models', [])
                for model in models:
                    if model['name'] == model_name:
                        return {
                            'name': model['name'],
                            'size': model.get('size', 0),
                            'modified': model.get('modified_at', ""),
                            'quantization': self._detect_quantization(model['name'])
                        }
        except Exception as e:
            print(f"Error getting model info: {e}")
            return None

    def _detect_quantization(self, model_name: str) -> str:
        """Detect quantization type from model name"""
        for quant in self.profiles.keys():
            if quant in model_name.lower():
                return quant
        return 'Unknown'

    def get_available_models(self) -> List[str]:
        """Return sorted available model names/tags from Ollama."""
        try:
            response = requests.get(f"{self.ollama_url}/api/tags", timeout=5)
            if response.status_code == 200:
                models = response.json().get('models', [])
                return sorted([model['name'] for model in models])
        except Exception as e:
            print(f"Error getting available models: {e}")
        # Fallback to empty indicates only current configured model is usable
        return []
